const body = $input.first().json;
const conversationId = String(body.conversation?.id ?? body.id ?? '');

// IDs dos grupos monitorados
// IMPORTANTE: Substituir 'CLINICA_CONV_ID' pelo ID real do grupo da Clínica no Chatwoot
// Como descobrir: abrir a conversa no Chatwoot e ver a URL: .../conversations/XXXX
const GRUPOS = {
  '4372': 'sstcard',
  '5590': 'clinica'
};

const grupo = GRUPOS[conversationId] || 'ignorar';

const content = body.content || '';
const ts = body.created_at ? new Date(body.created_at * 1000) : new Date();
const dataISO = ts.toISOString().split('T')[0];
const hora = ts.toTimeString().substring(0, 5);

// Formato Chatwoot grupo WhatsApp: '+55 7186844401 - Karine Santana: mensagem'
const regexGrupo = /^\+\d+[\s\d]+\s*-\s*(.+?):\s*([\s\S]+)$/;
const match = content.match(regexGrupo);

let senderName = 'Desconhecido';
let mensagem = content;

if (match) {
  senderName = match[1].trim().replace(/[\u{1F300}-\u{1FFFF}]/gu, '').trim();
  mensagem = match[2].trim();
}

const mapeamento = {
  'karine': 'Karine', 'raquel': 'Raquel', 'lucas': 'Lucas',
  'rogerio': 'Rogério', 'rogério': 'Rogério', 'mayko': 'Mayko'
};
let pessoa = senderName;
const nomeLower = senderName.toLowerCase();
for (const [chave, valor] of Object.entries(mapeamento)) {
  if (nomeLower.includes(chave)) { pessoa = valor; break; }
}

return [{
  json: {
    grupo,
    conversation_id: conversationId,
    message_id: String(body.id || ''),
    sender_name: senderName,
    pessoa,
    mensagem,
    content_original: content,
    data: dataISO,
    hora
  }
}];

const json = $input.first().json;
const mensagem = json.mensagem?.toLowerCase() || '';

const temNumero = /\d+/.test(mensagem);
const palavrasReporte = ['falei', 'fechei', 'paguei', 'pagaram', 'reativei', 'ativei',
  'lead', 'contato', 'adesão', 'adesao', 'reconciliação', 'reconciliacao',
  'parcial', 'resultado', 'hoje', 'vendeu', 'renovação', 'renovacao'];
const temPalavra = palavrasReporte.some(p => mensagem.includes(p));

if (!temNumero && !temPalavra) {
  return [{ json: { ...json, ignorar: true, motivo: 'sem_metricas_vendas' } }];
}
return [{ json: { ...json, ignorar: false } }];

