const msg = $input.all()[0].json;
const claudeResp = msg.content?.[0]?.text || '{}';

let metricas = {};
try {
  metricas = JSON.parse(claudeResp);
} catch (e) {
  const jsonMatch = claudeResp.match(/\{[\s\S]+\}/);
  if (jsonMatch) { try { metricas = JSON.parse(jsonMatch[0]); } catch(e2) {} }
}

const extraido = $('[SST Card] Filtrar Relevância').first().json;
const tipo = metricas.tipo || 'reporte-espontaneo';
const pessoa = extraido.pessoa || 'Desconhecido';
const data = extraido.data;
const hora = extraido.hora;

return [{
  json: {
    titulo: `${pessoa} | ${tipo} | ${data} ${hora}`,
    pessoa, tipo, data, hora,
    falou_com: metricas.falou_com ?? null,
    fechamentos: metricas.fechamentos ?? null,
    reativacoes: metricas.reativacoes ?? null,
    leads_gerados: metricas.leads_gerados ?? null,
    ativacoes: metricas.ativacoes ?? null,
    observacao: metricas.observacao || '',
    confianca: metricas.confianca || 'media',
    content_original: extraido.content_original,
    conversation_id: extraido.conversation_id,
    message_id: extraido.message_id
  }
}];

const json = $input.first().json;
const mensagem = json.mensagem?.toLowerCase() || '';

// Para a Clínica, ser mais permissivo: capturar qualquer conteúdo operacional ou comercial
const temNumero = /\d+/.test(mensagem);
const palavrasOp = ['atendimento', 'consulta', 'exame', 'paciente', 'medico', 'médico',
  'fila', 'agenda', 'cancelamento', 'cancelou', 'procedimento', 'laudo', 'resultado',
  'raio', 'ultrassom', 'anestesia', 'urgente', 'emergência', 'emergencia', 'quebrou'];
const palavrasCom = ['card', 'adesão', 'adesao', 'cadastro', 'pagamento', 'mensalidade',
  'plano', 'fechei', 'vendeu', 'renovação', 'renovacao', 'sstcard'];
const palavrasGeral = ['hoje', 'amanhã', 'amanha', 'decidimos', 'vamos fechar', 'problema',
  'solução', 'solucao', 'conseguimos', 'terminamos', 'fizemos', 'atenção', 'atencao'];

const relevante = temNumero ||
  palavrasOp.some(p => mensagem.includes(p)) ||
  palavrasCom.some(p => mensagem.includes(p)) ||
  palavrasGeral.some(p => mensagem.includes(p));

if (!relevante || mensagem.length < 5) {
  return [{ json: { ...json, ignorar: true, motivo: 'sem_conteudo_relevante_clinica' } }];
}
return [{ json: { ...json, ignorar: false } }];

