  "confianca": "alta" | "media" | "baixa"
}

Notas importantes:
- orcamentos_dia e convertidos: extrair só o número (ex: '$983,00' → 983, '$1.599,00' → 1599)
- taxa_conversao: extrair percentual como float (ex: '40,5%' → 40.5, '0,00%' → 0)
- bloqueador: preencher apenas quando há objeção ou impedimento explícito relatado
- tipo 'meta' quando o texto fala de objetivo ou alvo do dia

Exemplos:
- 'orçamentos: $983, convertidos: $1.599, taxa: 0%' → {tipo: 'final-dia', orcamentos_dia: 983, convertidos: 1599, taxa_conversao: 0}
- 'ligações feitas: 0, mensagens enviadas: 4' → {ligacoes_feitas: 0, mensagens_enviadas: 4}
- 'bloqueador: pacientes dizem que outros labs são mais baratos' → {tipo: 'bloqueador', bloqueador: 'Pacientes comparam preço com laboratórios concorrentes'}
- 'meta 40%+ de conversão' → {tipo: 'meta', meta_dia: '40% de taxa de conversão'}",
  "messages": [
    {
      "role": "user",
      "content": "Pessoa: {{ $json.pessoa }}
Mensagem: {{ $json.mensagem }}
Data: {{ $json.data }} {{ $json.hora }}"
    }
  ]
}

